var e=JSON.parse(`[{"id":"idx_0","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. VCDF002S07056-10\\n<color=#ffd34c>2급 요인</color> 열람 승인 자료\\n부록: 대상자 주변인 증언","JPN":"CN No. VCDF002S07056-10\\n<color=#ffd34c>2級要因</color> 閲覧承認資料\\n付録: 対象者周辺人証言","ENG":"CN No. VCDF002S07056-10\\n<color=#ffd34c>Class 2 Factor</color> Review Approval Documents\\nAppendix: Testimonies from Acquaintances of the Subject","TWN":"(TWN)CN No. VCDF002S07056-10\\n<color=#ffd34c>2급 요인</color> 열람 승인 자료\\n부록: 대상자 주변인 증언"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_1","type":"dialog","speaker":null,"text":{"KOREA":"그 어린 자매님이요. 네, 기억하고 말고요.","JPN":"その幼い姉妹様です。はい、記憶してしまって。","ENG":"That young Sister? Yes, of course I remember her.","TWN":"(TWN)그 어린 자매님이요. 네, 기억하고 말고요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_2","type":"dialog","speaker":null,"text":{"KOREA":"저는 주말마다 다른 분들과 함께 수녀원 일을 도우러 다녔어요. 몇 년 전까지는 건강했거든요.","JPN":"私は週末ごとに他の方々とともに修道院事を助けに歩きました。何年前までは元気だったんですよ。","ENG":"I used to go help out at the convent with others every weekend. I was healthy until just a few years ago.","TWN":"(TWN)저는 주말마다 다른 분들과 함께 수녀원 일을 도우러 다녔어요. 몇 년 전까지는 건강했거든요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_3","type":"dialog","speaker":null,"text":{"KOREA":"수녀원에 가면 항상 자매님이 마중을 나오셨죠.","JPN":"修道院に行けば常に姉妹様が出迎えを出たんです。","ENG":"Whenever I went to the convent, Sister would always come out to greet me.","TWN":"(TWN)수녀원에 가면 항상 자매님이 마중을 나오셨죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_4","type":"dialog","speaker":null,"text":{"KOREA":"지금도 생각 나요. 만날 때마다 어쩜 저렇게 예쁘게 웃으시나 했어요.","JPN":"今も思い出します。会う度にどうしてああにきれいに笑うがしました。","ENG":"I still think about it. I wondered how she could smile so beautifully every time we met.","TWN":"(TWN)지금도 생각 나요. 만날 때마다 어쩜 저렇게 예쁘게 웃으시나 했어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_5","type":"dialog","speaker":null,"text":{"KOREA":"한 번은 직접 물어봤죠. 수녀원에서 지내기 갑갑하지 않느냐고.","JPN":"一回は直接聞いてみたんです。修道院で過ごす窮屈でないと。","ENG":"I asked her once directly. Whether it wasn't stifling living at the convent.","TWN":"(TWN)한 번은 직접 물어봤죠. 수녀원에서 지내기 갑갑하지 않느냐고."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_6","type":"dialog","speaker":null,"text":{"KOREA":"한창 뛰어놀 나이에 바깥 세상과 떨어져서 지낸다는 게 어떤 기분일지 짐작도 안 갔거든요.","JPN":"盛んに飛び回って遊ぶ年齢に外界と落ちて過ごすというのがどのような気分かも見当もつかなかったんですよ。","ENG":"I couldn't even imagine what it would feel like to be separated from the outside world at an age when you should be out playing.","TWN":"(TWN)한창 뛰어놀 나이에 바깥 세상과 떨어져서 지낸다는 게 어떤 기분일지 짐작도 안 갔거든요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_7","type":"dialog","speaker":null,"text":{"KOREA":"이 늙은인 여기 병원에만 있기도 갑갑한데.","JPN":"この老けたであるここに病院にだけあったり窮屈であるが。","ENG":"This old person feels stifled just staying here in the hospital.","TWN":"(TWN)이 늙은인 여기 병원에만 있기도 갑갑한데."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_8","type":"dialog","speaker":null,"text":{"KOREA":"그랬더니만 자매님이 웃으면서 봉사 나가느라 그렇게 갑갑한지 모르겠다고 하셨죠.","JPN":"そういったところだけ姉妹様が笑って奉仕出るためにそのように窮屈なのか知らないと言ったんです。","ENG":"But Sister just smiled and said she didn't feel stifled because she went out to serve.","TWN":"(TWN)그랬더니만 자매님이 웃으면서 봉사 나가느라 그렇게 갑갑한지 모르겠다고 하셨죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_9","type":"dialog","speaker":null,"text":{"KOREA":"병원에, 요양원에, 보육 시설에....... 그 나이 때도 한창 정정하신 수녀님들 못지않게 힘쓰셨어요.","JPN":"病院に、療養院に、保育施設に.......その年齢時も盛んに訂正した修道女皆さんに劣らず力をつくしました。","ENG":"To hospitals, nursing homes, childcare facilities....... Even at that age, she worked as hard as the Sisters in their prime.","TWN":"(TWN)병원에, 요양원에, 보육 시설에....... 그 나이 때도 한창 정정하신 수녀님들 못지않게 힘쓰셨어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_10","type":"dialog","speaker":null,"text":{"KOREA":"늙은이도 이런저런 작은 일을 하고 있었는데, 그 얘길 듣고 깜짝 놀랐어요.","JPN":"老人もあらゆる小さな事をしていたが、その話を聞いてびっくりしました。","ENG":"I was doing small tasks here and there despite being old, but I was surprised to hear that.","TWN":"(TWN)늙은이도 이런저런 작은 일을 하고 있었는데, 그 얘길 듣고 깜짝 놀랐어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_11","type":"dialog","speaker":null,"text":{"KOREA":"주님의 일을 행한다고 하지만, 사람 마음이 언제 교만해질지 모르거든요.","JPN":"神様の事を行うと言うが、人心がいつ驕慢になるかもしれないんですよ。","ENG":"They say they do the Lord's work, but you never know when the human heart might become arrogant.","TWN":"(TWN)주님의 일을 행한다고 하지만, 사람 마음이 언제 교만해질지 모르거든요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_12","type":"dialog","speaker":null,"text":{"KOREA":"내가 이렇게 어려운 사람을 돕는다, 내가 이렇게 신실하다, 그런 생각이 하나하나 쌓이면 어느새 주님의 일을 자랑거리로 여기는 거예요.","JPN":"私がこのように難しい人を助ける、私がこのように信実する、そんな考えが一つ一つ積もればいつのまにか神様の事を自慢の種と思うことです。","ENG":"'I help people in such difficulty,' 'I am this faithful'—when such thoughts pile up one by one, before you know it, you come to treat the Lord's work as something to boast about.","TWN":"(TWN)내가 이렇게 어려운 사람을 돕는다, 내가 이렇게 신실하다, 그런 생각이 하나하나 쌓이면 어느새 주님의 일을 자랑거리로 여기는 거예요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_13","type":"dialog","speaker":null,"text":{"KOREA":"그런데 자매님은 그렇지 않았어요. 어려운 사람을 돕는 건 당연하다고 생각했죠.","JPN":"ところで姉妹様はそうでなかったです。難しい人を助けるのは当然であると思ったんです。","ENG":"But Sister wasn't like that. She thought helping those in difficulty was only natural.","TWN":"(TWN)그런데 자매님은 그렇지 않았어요. 어려운 사람을 돕는 건 당연하다고 생각했죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_14","type":"dialog","speaker":null,"text":{"KOREA":"시국으로 떠나실 때 참 많은 사람들이 배웅해 주러 나왔어요. 모두 자매님을 통해 주님의 은혜를 접한 분들이었죠.","JPN":"時局に発つ時本当に多くの人が見送ってくれに出ました。皆姉妹様を通じて神様の恩恵を接した方々でした。","ENG":"When she left for the countryside, so many people came out to see her off. They were all people who had received the Lord's grace through Sister.","TWN":"(TWN)시국으로 떠나실 때 참 많은 사람들이 배웅해 주러 나왔어요. 모두 자매님을 통해 주님의 은혜를 접한 분들이었죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_15","type":"dialog","speaker":null,"text":{"KOREA":"주님의 일은 연륜이나 지식이 아니라 진심으로 행해야 이루어진다는 걸 그때 느꼈어요.","JPN":"神様の事は年輪や知識ではなく心より行ってこそ成り立つというものをあの時感じました。","ENG":"That's when I felt that the Lord's work is accomplished not by experience or knowledge, but by sincerity.","TWN":"(TWN)주님의 일은 연륜이나 지식이 아니라 진심으로 행해야 이루어진다는 걸 그때 느꼈어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_16","type":"dialog","speaker":null,"text":{"KOREA":"시국에서도 잘 지내셨으면 좋겠네요.","JPN":"時局でも元気だったら良いですね。","ENG":"I hope she's doing well in the countryside too.","TWN":"(TWN)시국에서도 잘 지내셨으면 좋겠네요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_17","type":"dialog","speaker":null,"text":{"KOREA":"████. ██. ██ <color=#ff3636>대상의 사망으로 3차 면회는 중지되었음을 기재함.</color>","JPN":"████。██。██ <color=#ff3636>対象の死亡で３次面会は中止されたことを記載する。</color>","ENG":"████. ██. ██ <color=#ff3636>Record that the 3rd interview was suspended due to the subject's death.</color>","TWN":"(TWN)████. ██. ██ <color=#ff3636>대상의 사망으로 3차 면회는 중지되었음을 기재함.</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};